INSERT INTO "public"."projects" ("id", "title", "year", "company", "role", "description", "lessons", "image_url", "order_index", "category", "is_unlocked", "published", "created_at", "updated_at", "phase", "project_type", "situation", "task", "result", "contributions", "key_results", "tags", "metrics", "company_url", "project_url", "report_url", "demo_url", "company_urls", "project_urls", "report_urls", "demo_urls", "company_label", "project_label", "report_label", "demo_label", "video_poster", "video_fallback") VALUES ('01e24e49-8441-433d-8acd-f66bae37f315', 'Analyst Curation Ecosystem', 2026, 'Moncho', 'Full Stack Engineer', 'Designed "The Curator''s OS," a multi-player curation system enabling external analysts to verify, refine, and scale the Moncho database through a secure sandboxed environment.', null, null, 26, 'Platform Engineering', true, true, '2026-03-23 12:21:07.385552+00', '2026-03-23 12:31:18.116816+00', 'Scale', 'System Architecture', 'Transitioning from an internal-only data model to a scalable crowdsourced expert network required a robust "Human-in-the-Loop" validation system to maintain data integrity.', '- Designed a Change Request and Audit Log architecture that sandboxes AI-generated and user-submitted market data.
- Built a dedicated Analyst API workflow enabling researchers to safely push validated JSON data to a staging queue for admin review.', '- Shifted market intelligence collection from single-player manual entry to a scalable, multi-player expert network.
- Established an immutable, transparent record of truth for emerging market data with exact contributor attribution.', '[{"type": "System Design", "contribution": "Architected the Change Request and Audit Log system for strict data governance.", "value_chain_position": "upstream"}, {"type": "API Design", "contribution": "Developed secure ingestion APIs for local analyst scripts to sync with the central database.", "value_chain_position": "downstream"}]', '[{"label": "Data Integrity", "value": "100% Verified", "category": "Security", "description": "Ensured production data is protected via sandboxed staging and mandatory admin review loops."}, {"label": "Scalability", "value": "Multi-player", "category": "Growth", "description": "Decoupled data collection from internal bottlenecks securely."}]', ARRAY['system architecture','api development','human-in-the-loop','postgresql','typescript','data governance'], '{"security": "Sandboxed API ingestion", "data_model": "Relational staging tables", "system_role": "Analyst Staging Environment", "transparency": "Immutable database audit logs", "verification": "Human-in-the-loop change requests"}', 'https://www.moncho.ai', 'https://github.com/shmukit/Moncho-Analysts', null, null, '[]', '[]', '[]', '[]', 'Moncho.ai', 'Moncho Analysts GitHub', null, null, null, null), ('1c04c3aa-d61b-4bc9-9984-74eac1cd0e99', 'Gamification System', 2024, '10 Minute School', 'Lead Product Manager', 'Designed gamification framework and behavioral design system for motivating learning streaks and engagement.', 'Gamification works when tied to intrinsic learning motivation, not vanity points.', '/images/projects/gamification-system.png', 12, 'Behavioral & Gamification', true, true, '2025-10-15 18:53:23.30044+00', '2025-10-22 17:08:09.560908+00', 'Feature Suit', 'Strategy', '10MS did not have a detailed plan to scale the gamification system, particularly for converter and drainage system in the game economy. ', 'Planned gamified system based on game economy, proper drainage/converter system and MDA (Mechanism > Design > Aesthetics) philosophy to achieve learning outcome and commercial goals.', 'Clarity & Scaleable plan to build cascade of features and gamification system on the platform. ', '[{"type": "UX Design", "contribution": "Created gamification playbook", "value_chain_position": "upstream"}, {"type": "Data Analysis", "contribution": "Mapped behavioral triggers", "value_chain_position": "upstream"}, {"type": "Decision Strategy", "contribution": "Collaborated with design & data teams", "value_chain_position": "downstream"}]', null, ARRAY['gamification','behavioral-design','strategy','learning-engagement','motivation'], '{"features": "Badges", "feature_count": 3}', null, null, null, null, '[]', '[]', '[]', '[]', null, null, null, null, null, null), ('2ac37748-ee57-45ea-87c4-9daf580e0c58', 'IDRC: EdTech Policy Platform for SEA', 2025, 'mPower x IDRC', 'Consultant X Co-PI', 'Multi-country research to strengthen policymakers capacities for appropriate EdTech integration.', 'Policy research requires understanding both technical feasibility and political implementation challenges.', null, 16, 'Research, Policy & Tech', true, true, '2025-10-17 09:56:44.34014+00', '2025-12-29 13:15:54.343012+00', 'Research
', 'Tech Policy & Platform', 'In SEA, due to policymakers lacked contextual frameworks & platform for assessing EdTech tools and making evidence-based integration decisions.', 'Designed frameworks for EdTech usage assessment, decision-making capability evaluation, and tech platform to find contextualized Edtech solutions for policymakers.', 'Research and Tech platform development ongoing. ', '[{"type": "Research", "contribution": "Designing EdTech tools assessment frameworks", "value_chain_position": "upstream"}, {"type": "Tech Platform", "contribution": "Developing tech platform for policymakers to pick Edtech tools.", "value_chain_position": "downstream"}]', '[{"label": "Research Scope", "value": "South-East Asia", "category": "Scale", "description": "Bangladesh, Sri-Lanka, Vietnam, Cambodia, Phillipines, etc."}, {"label": "Current Status", "value": "Research Phase", "category": "Development", "description": "Cross-country analysis ongoing"}]', ARRAY['research','policy','edtech','policy frameworks','Tech4Dev'], '{"status": "synthesis", "countries": "multiple", "deliverables": "bangladesh_complete"}', null, null, null, null, '[]', '[{"url": "https://idrc-crdi.ca/en/initiative/empowered-technology-inclusive-education", "label": "EmpowerED: Technology for Inclusive Education", "description": "Strengthening decision-makers’ capacities for appropriate EdTech use in South and Southeast Asia — Bangladesh"}]', '[]', '[]', null, null, null, null, null, null), ('311ff767-659b-4ce3-b0a6-37f38078843a', 'Booking Management System', 2025, '10 Minute School', 'Consultant 
', 'A comprehensive system for booking speaking tests, free classes, CBT mock tests, and managing slots. Stakeholders: students, teachers, branch admins, super-admins.', 'Complex multi-stakeholder systems require clear role-based permissions and intuitive admin interfaces.', null, 18, 'EdTech Platform', true, false, '2025-10-17 09:56:44.34014+00', '2025-10-21 21:32:37.452004+00', 'Prototype', 'Booking Management System', 'Students needed streamlined booking system for speaking tests, free classes, and CBT mock tests across multiple locations.', 'Designed UX flow, slot management logic, and admin-side controls for 4-sided marketplace complexity.', 'Prototyped and demo-ready in 3 weeks (part-time) despite 4-sided complexity of students, teachers, branch admins, and super-admins.', '[{"type": "UX Design", "contribution": "Designed UX flow for multi-stakeholder booking system", "value_chain_position": "upstream"}, {"type": "Data Analysis", "contribution": "Built slot management logic for complex scheduling", "value_chain_position": "upstream"}, {"type": "Decision Strategy", "contribution": "Created admin-side controls for 4-sided marketplace", "value_chain_position": "downstream"}]', '[{"label": "Development Time", "value": "3 Weeks", "category": "Efficiency", "description": "Prototype to development"}, {"label": "Marketplace Complexity", "value": "4-sided", "category": "Architecture", "description": "Students, teachers, branch admins, super-admins"}, {"label": "Current Status", "value": "Demo Ready", "category": "Development", "description": "Prototype completed and functional"}]', ARRAY['booking-system','edtech','multi-stakeholder','scheduling','admin-dashboard','prototype','Forward Deployed Engineer'], '{"status": "demo_ready", "timeline": "3_weeks", "complexity": "4_sided"}', null, null, null, null, '[]', '[]', '[]', '[]', null, null, null, null, null, null), ('31339193-fc68-4fa7-a4d8-db496ccf97a8', 'Teaching at the Right Level (TaRL)', 2024, '10 Minute School x Monash University', 'Lead Product Manager', 'Developed the TARA app using Teaching at the Right Level (TaRL) methodology for adaptive learning system for class 3-5 kids learning Math and English.', 'Adaptive learning systems are most effective when grounded in proven pedagogy like TaRL, especially for foundational subjects.', '/images/projects/rct-tara-app.png', 9, 'Learning Science & Pedagogy', true, true, '2025-10-15 18:53:23.30044+00', '2025-10-20 15:31:14.199961+00', 'Feature Suit', 'RCT', 'Class 3-5 students lacked adaptive learning support aligned with their actual learning levels in Math and English.', 'Build and pilot TARA app using TaRL methodology in collaboration with Monash researchers.', 'Project paused but it helped to develop a comprehensive and dynamic adaptive learning system for 10 Minute School. ', '[{"type": "Data Analysis", "contribution": "Co-led RCT design for TaRL methodology", "value_chain_position": "upstream"}, {"type": "UX Design", "contribution": "With the help of design team led the development of the prototype.", "value_chain_position": "upstream"}, {"type": "Decision Strategy", "contribution": "Managed Monash collaboration and research coordination", "value_chain_position": "downstream"}]', '[{"label": "Students Planned to onboard", "value": "3,000+", "category": "Scale", "description": "Class 3-5 students in RCT pilot"}, {"label": "Pilot Type", "value": "Temporarily Paused.", "category": "Research", "description": "Randomized Controlled Trial"}, {"label": "Methodology", "value": "TaRL", "category": "Innovation", "description": "Teaching at the Right Level"}, {"label": "Subjects", "value": "Math & English", "category": "Curriculum", "description": "Core subjects for class 3-5"}]', ARRAY['adaptive-learning','UI/UX','taRL','gamification','research'], '{"subjects": "Math & English", "methodology": "TaRL", "target_grade": "3-5", "collaboration": "Monash University", "pilot_outcome": "paused"}', null, null, null, null, '[]', '[]', '[]', '[]', null, null, null, null, null, null), ('34f858ee-96a4-4e9e-a30d-f20fb79bff8f', 'Unibiome (France)', 2016, 'Unibiome SAS', 'Co-founder & COO', 'Unibiome (previously known as Peer to Peer Probiotics): Engineered fermentative microbes using synthetic and molecular biology to fortify foods with micronutrients. Later discontinued.', 'Learned how science and venture capital intersect through experimentation.', '/images/projects/unibiome-vitamins-chart.jpg', 8, 'Biotech', true, true, '2025-10-15 18:53:23.30044+00', '2025-10-21 14:52:20.342887+00', 'Startup', 'Synthetic biology', 'We won gold medal for our iGEM 2015 project as part of Paris Bettencourt team. The key idea was to engineer fermentative microbes to fortify foods with micronutrients like vitamins and iron.', 'I was one of the cofounders and COO.', 'Got 100K USD fund, participated in Rebelbio startup accelerator, Ireland in 2016. Special Prize for "International Potential", Genopole Young Biotech Prize 2016, France. Won 30K Euro Grant. Kirchner Food Fellowship in Thought for Food (TFF) Global Summit 2016, Zurich, Switzerland. Top 500 Deep Tech Start-ups in the world by Hello Tomorrow Summit 2016, Paris, France.', '[{"type": "Decision Strategy", "contribution": "Business Development & application for funding, competitions, grants", "value_chain_position": "upstream"}]', '[{"label": "Funding Raised", "value": "$100K", "category": "Financial", "description": "From RebelBio accelerator"}, {"label": "Grant Won", "value": "€30K", "category": "Financial", "description": "Genopole Young Biotech Prize, France"}, {"label": "Deep Tech Start-ups", "value": "Top 500", "category": "Recognition", "description": "Hello Tomorrow Summit 2016"}, {"label": "iGEM 2015, MIT, USA", "value": "Gold Medal", "category": "Recognition", "description": "Paris Bettencourt team"}]', ARRAY['biotech','entrepreneurship','probiotics','synthetic-biology'], '{"sector": "Biotech", "status": "discontinued", "funding": "$100K", "location": "France"}', null, null, null, null, '[]', '[{"url": "https://thisismold.com/process/cook/unibiome-biotech-startup-is-tackling-malnutrition-with-engineered-probiotics", "label": "MOLD Article - Unibiome BioTech Startup", "description": "How This BioTech Startup is Tackling Malnutrition with Engineered Probiotics"}]', '[]', '[]', null, 'Media', null, null, null, null), ('35acac9a-c75b-4f11-a023-78d238accf08', 'In Stealth Edtech Platform (A/O Levels - B2C)', 2025, 'mPower', 'Consulant', 'Personalized exam prep and progress tracking for A/O level students with integrated assessment analytics. Developed digital distribution channels and growth strategies for scalable user acquisition.', 'Student-focused design requires balancing personalization with simplicity. Digital distribution channels must align with student behavior and parent decision-making patterns.', null, 19, 'Rapid Prototyping', true, true, '2025-10-17 09:56:44.34014+00', '2025-10-22 14:06:26.792109+00', 'Prototype', 'Global B2C Edtech', 'A/O level students needed personalized exam preparation and progress tracking tools. ', 'Conducted 30+ teachers/student interviews and competitor analysis; designed student experience and MVP for personalized learning. ', 'Handed off design for development in 3 weeks — reduced MVP delivery timeline from 1 year to 1 month for client. Assisting in scalable digital distribution framework for user acquisition.
', '[{"type": "Data Analysis", "contribution": "Conducted 30+ interviews for user research", "value_chain_position": "upstream"}, {"type": "Data Analysis", "contribution": "Performed competitor analysis for market positioning", "value_chain_position": "upstream"}, {"type": "UX Design", "contribution": "Rapid Prototyping through AI tools.", "value_chain_position": "upstream"}]', '[{"label": "Design Timeline", "value": "3 Weeks", "category": "Efficiency", "description": "Complete UX design and research"}, {"label": "Timeline Reduction", "value": "1 Year → 1 Month", "category": "Impact", "description": "MVP delivery acceleration"}, {"label": "User Research", "value": "30+ Interviews", "category": "Research", "description": "Student interviews conducted"}, {"label": "Distribution Strategy", "value": "Multi-Channel", "category": "Growth", "description": "Organic and Inorganic."}]', ARRAY['vibe coding','rapid prototyping','user research','Forward Deployed Engineer','strategy','distribution'], '{"interviews": 8, "design_time": "3_weeks", "growth_framework": "scalable", "timeline_reduction": "12_to_1_month", "distribution_channels": "multi_channel"}', null, null, null, null, '[]', '[]', '[]', '[]', null, null, null, null, null, null), ('379c7eac-3a2d-4443-8518-61e9ef0936e4', 'Course Recommendation System', 2023, '10 Minute School', 'Lead Product Manager', 'Personalized recommendation engine for paid and free users based on user behavior and conversion probability.', 'Recommendation algorithms must balance user value with business objectives to drive sustainable growth.', null, 20, 'Personalization & ML', true, false, '2025-10-17 09:56:44.34014+00', '2025-10-17 22:01:00.607297+00', 'Live', 'Recommendation Engine', 'Users received generic course recommendations that didn''t match their learning goals or conversion likelihood.', 'Designed logic for differential recommendation between free vs. paid users based on behavior and conversion probability.', 'Improved conversion predictability and retention through adaptive recommendations tailored to user segments.', '[{"type": "Data Analysis", "contribution": "Designed differential recommendation logic for free vs. paid users", "value_chain_position": "upstream"}, {"type": "Data Analysis", "contribution": "Built conversion probability models", "value_chain_position": "upstream"}, {"type": "Decision Strategy", "contribution": "Implemented adaptive recommendation algorithms", "value_chain_position": "downstream"}]', '[{"label": "Conversion Predictability", "value": "Improved", "category": "Business Impact", "description": "Better targeting of high-conversion users"}, {"label": "Retention", "value": "Enhanced", "category": "User Impact", "description": "Adaptive recommendations drive engagement"}, {"label": "Recommendation Logic", "value": "Differential", "category": "Features", "description": "Free vs. paid user segmentation"}]', ARRAY['recommendation-engine','personalization','ml','conversion-optimization','user-segmentation','retention'], '{"retention": "enhanced", "segmentation": "differential", "conversion_predictability": "improved"}', null, null, null, null, '[]', '[]', '[]', '[]', null, null, null, null, null, null), ('4d1d38e4-5fe8-4b8f-9b05-46049011ea76', 'GenAI English Speaking Feature', 2025, '10 Minute School', 'Lead Product Manager', 'Developed an English-speaking GenAI feature for Bangla learners, focusing on contextual practice and feedback.', 'GenAI speaking tools must balance linguistic accuracy with emotional confidence building.', null, 11, 'GenAI & Language Learning', true, true, '2025-10-15 18:53:23.30044+00', '2026-03-23 09:49:44.88072+00', 'Feature Suit', 'AI Product Dev', 'Bangladeshi students lacked affordable, interactive & locally contextual English-speaking practice platform.', 'Design, train, and pilot GenAI conversational tutor in English learning course based on 30 real life scenarios. ', 'Pilot ongoing.', '[{"type": "AI Product Dev", "contribution": "Defined AI product spec", "value_chain_position": "upstream"}, {"type": "LLM", "contribution": "Assisted with LLM Gaurdrails", "value_chain_position": "upstream"}, {"type": "AI UI/UX", "contribution": "AI Learning UX Development", "value_chain_position": "downstream"}]', '[{"label": "Status", "value": "Pilot Ongoing", "category": "Pilot", "description": "30 Scenarios"}, {"label": "Speech Pipeline", "value": "STT-LLM-TTS", "category": "GenAI Architecture", "description": "Speech-to-Text → Large Language Model → Text-to-Speech (STT-LLM-TTS) pipeline. Turn-taking is stabilized with VAD + Semantic Turn Detection (STD) to avoid awkward pauses inside the STT-LLM-TTS tutoring loop."}]', ARRAY['genai','prompt engineering','UX Design','conversational-ai'], '{"status": "Pilot"}', null, null, 'https://medium.com/@uttamdeb670/ai-voice-agents-part-1-the-story-of-two-approaches-297d68ac7855', null, '[]', '[]', '[]', '[]', null, null, null, null, null, null), ('4ee5efb8-697f-45f3-a083-4d80e612bcec', '10MS Brand Recall Survey', 2024, '10 Minute School x Innovision Consulting', 'Lead Product Manager', 'Conducted comprehensive brand recall and pricing sensitivity survey across Bangladesh to understand market positioning and optimal pricing for English and Tech products.', 'Brand recall surveys provide crucial insights for market expansion and pricing strategy, especially in emerging edtech markets.', null, 22, 'Brand Recall', true, true, '2025-10-23 05:21:45.555126+00', '2025-10-23 05:35:52.003787+00', 'Research', 'Market Research', 'We wanted to understand 10MS brand recall & pricing sensitivity across Bangladesh particularly in some key regions to expand English and Tech business.', 'Designed survey for 2300 respondents across Bangladesh, in 3 divisions- Dhaka, Chittagong, Sylhet. Product categories- Kids English, IELTS and Tech Skills. Pricing Analysis method: Van Westerndorp''s price sensitivity meter.', 'Brand recall across Tech courses & English Product categories- 22 to 25% and particularly in IELTS highest 31%.', '[{"type": "Research Planning", "contribution": "Designed comprehensive survey methodology and respondent selection strategy", "value_chain_position": "upstream"}, {"type": "Questionnaire Development", "contribution": "Developed survey questions and Van Westerndorp pricing analysis framework", "value_chain_position": "upstream"}, {"type": "Data Analysis & Report Preparation", "contribution": "Analyzed survey data and prepared comprehensive market insights report", "value_chain_position": "downstream"}]', '[{"label": "Brand Recall - IELTS Product", "value": "31%", "category": "Brand Performance", "description": "Highest brand recall among all product categories"}, {"label": "Brand Recall - English & Tech Courses", "value": "22-25%", "category": "Brand Performance", "description": "Strong brand recognition in edtech."}, {"label": "Survey Scale", "value": "2,300", "category": "Research", "description": "Respondents across 3 major divisions"}]', ARRAY['Market Research','User Research','Pricing Research','Brand Recall'], '{"methodology": "Van Westerndorp", "survey_scale": "2,300 respondents", "brand_recall_tech": "22-25%", "divisions_covered": 3, "brand_recall_ielts": "31%", "product_categories": 3}', null, null, null, null, '[]', '[]', '[]', '[]', null, null, null, null, null, null), ('6665081a-dd35-4fe7-ac0a-ec2886cce3b5', 'Gamification: Financial Literacy Course
